/**
 * Kim-Cookie-Parser Crypto Plugin Interface (kcookie_crypto.h)
 * Pluggable signature algorithm support
 *
 * @author Kim AI Empire
 * @version 1.1.0
 * @date 2026-01-19
 */

#ifndef KCOOKIE_CRYPTO_H
#define KCOOKIE_CRYPTO_H

#include <stddef.h>

/* ==================== Algorithm Types ==================== */

typedef enum {
    KCOOKIE_HASH_FNV1A,      // Fast, simple hash (default, v1.0.0 compat)
    KCOOKIE_HASH_HMAC_SHA256 // Production-grade HMAC-SHA256
} kcookie_hash_algorithm_t;

/* ==================== Crypto Provider Interface ==================== */

/**
 * Crypto provider structure (function pointers)
 */
typedef struct {
    kcookie_hash_algorithm_t algorithm;
    const char *name;  // "FNV-1a" or "HMAC-SHA256"

    /**
     * Sign a value
     * @param value Value to sign
     * @param secret Secret key
     * @param output Signed value (output, format: "s:value.signature")
     * @param size Output buffer size
     * @return 0 on success, -1 on error
     */
    int (*sign)(const char *value, const char *secret,
                char *output, size_t size);

    /**
     * Verify and unsign a value
     * @param signed_value Signed value (format: "s:value.signature")
     * @param secret Secret key
     * @param output Unsigned value (output)
     * @param size Output buffer size
     * @return 0 on success, -1 on verification failure
     */
    int (*verify)(const char *signed_value, const char *secret,
                  char *output, size_t size);

    /**
     * Get signature length (in hex characters)
     * @return Signature length (16 for FNV-1a, 64 for HMAC-SHA256)
     */
    size_t (*signature_length)(void);
} kcookie_crypto_provider_t;

/* ==================== Global Provider Management ==================== */

/**
 * Set global crypto provider
 * @param provider Crypto provider (or NULL to reset to default FNV-1a)
 */
void kcookie_set_crypto_provider(kcookie_crypto_provider_t *provider);

/**
 * Get current crypto provider
 * @return Current provider
 */
kcookie_crypto_provider_t* kcookie_get_crypto_provider(void);

/* ==================== Built-in Providers ==================== */

/**
 * FNV-1a provider (default, v1.0.0 compatible)
 * - Fast: 2M signatures/sec
 * - Signature: 16 hex characters
 * - Security: Simple hash, not cryptographically secure
